#!/usr/bin/env node
// Apply portable iOS signing settings to the generated Tauri/Xcode project and
// keep generated app icons in sync with the canonical Tauri icon set.

import {
  copyFileSync,
  existsSync,
  mkdirSync,
  readFileSync,
  readdirSync,
  unlinkSync,
  writeFileSync,
} from 'node:fs';
import { execFileSync } from 'node:child_process';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const PROFILE_PATH = process.env.MOONSHINE_IOS_PROFILE;
const PROFILE_NAME = process.env.MOONSHINE_IOS_PROFILE_NAME;
const PROFILE_UUID = process.env.MOONSHINE_IOS_PROFILE_UUID;
const TEAM_ID = process.env.MOONSHINE_IOS_TEAM_ID ?? 'TE7GQ963TQ';
const BUNDLE_ID = 'ai.forkjoin.moonshine';
const URL_SCHEME = 'moonshine';

const appDir = dirname(dirname(fileURLToPath(import.meta.url)));
const appleDir = join(appDir, 'src-tauri/gen/apple');
const projectPath = join(appleDir, 'project.yml');
const externalsDir = join(appleDir, 'Externals');
const sourceIconDir = join(appDir, 'src-tauri/icons/ios');
const generatedIconDir = join(appleDir, 'Assets.xcassets/AppIcon.appiconset');
const generatedIconContentsPath = join(generatedIconDir, 'Contents.json');

if (!existsSync(projectPath)) {
  console.error(`[patch-ios-signing] not found: ${projectPath}\nRun \`tauri ios init\` first.`);
  process.exit(1);
}

if (PROFILE_PATH && PROFILE_UUID) {
  if (existsSync(PROFILE_PATH)) {
    const installDir = join(process.env.HOME ?? '', 'Library/MobileDevice/Provisioning Profiles');
    mkdirSync(installDir, { recursive: true });
    copyFileSync(PROFILE_PATH, join(installDir, `${PROFILE_UUID}.mobileprovision`));
  } else {
    console.warn(`[patch-ios-signing] profile not found at ${PROFILE_PATH}; relying on already-installed copy.`);
  }
}

let source = readFileSync(projectPath, 'utf8');
if (!source.includes(`PRODUCT_BUNDLE_IDENTIFIER: ${BUNDLE_ID}`)) {
  console.error('[patch-ios-signing] generated project is not Moonshine; refusing to patch.');
  process.exit(1);
}

const usesManualProfile = Boolean(PROFILE_NAME && PROFILE_UUID);
const signingBlock = [
  `        CODE_SIGN_STYLE: ${usesManualProfile ? 'Manual' : 'Automatic'}`,
  '        CODE_SIGN_IDENTITY: Apple Development',
  `        DEVELOPMENT_TEAM: ${TEAM_ID}`,
  ...(usesManualProfile
    ? [`        PROVISIONING_PROFILE: ${PROFILE_UUID}`, `        PROVISIONING_PROFILE_SPECIFIER: ${PROFILE_NAME}`]
    : []),
].join('\n');

source = source
  .replace(/        CODE_SIGN_STYLE: .*\n/g, '')
  .replace(/        CODE_SIGN_IDENTITY: .*\n/g, '')
  .replace(/        DEVELOPMENT_TEAM: .*\n/g, '')
  .replace(/        PROVISIONING_PROFILE: .*\n/g, '')
  .replace(/        PROVISIONING_PROFILE_SPECIFIER: .*\n/g, '');
source = source.replace(/^        VALID_ARCHS: arm64.*$/m, `        VALID_ARCHS: arm64\n${signingBlock}`);
source = source.replace(/(- script: ).*? ios xcode-script/g, '$1tauri ios xcode-script');

if (!source.includes('CFBundleURLTypes:')) {
  source = source.replace(
    '        CFBundleVersion: "0.1.0"\n',
    `        CFBundleVersion: "0.1.0"\n` +
      `        CFBundleURLTypes:\n` +
      `          - CFBundleURLName: ${BUNDLE_ID}\n` +
      `            CFBundleURLSchemes: [${URL_SCHEME}]\n`,
  );
}

writeFileSync(projectPath, source);
mkdirSync(externalsDir, { recursive: true });

try {
  execFileSync(process.env.XCODEGEN ?? 'xcodegen', ['generate', '--spec', 'project.yml'], {
    cwd: appleDir,
    stdio: 'inherit',
  });
} catch (error) {
  console.error('[patch-ios-signing] xcodegen failed.');
  process.exit(error.status || 1);
}

if (existsSync(sourceIconDir) && existsSync(generatedIconDir) && existsSync(generatedIconContentsPath)) {
  const contents = JSON.parse(readFileSync(generatedIconContentsPath, 'utf8'));
  const referencedIcons = new Set(
    contents.images
      ?.map((image) => image.filename)
      .filter((filename) => typeof filename === 'string') ?? [],
  );
  for (const fileName of readdirSync(generatedIconDir)) {
    if (fileName.endsWith('.png') && !referencedIcons.has(fileName)) {
      unlinkSync(join(generatedIconDir, fileName));
    }
  }
  let copied = 0;
  for (const fileName of referencedIcons) {
    if (!fileName.endsWith('.png')) continue;
    if (!existsSync(join(sourceIconDir, fileName))) continue;
    copyFileSync(join(sourceIconDir, fileName), join(generatedIconDir, fileName));
    copied += 1;
  }
  console.log(`[patch-ios-signing] synced ${copied} iOS app icons.`);
}

const exportOptionsPath = join(appleDir, 'ExportOptions.plist');
writeFileSync(
  exportOptionsPath,
  `<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
\t<key>method</key>
\t<string>debugging</string>
\t<key>teamID</key>
\t<string>${TEAM_ID}</string>
\t<key>signingStyle</key>
\t<string>${usesManualProfile ? 'manual' : 'automatic'}</string>
${
  usesManualProfile
    ? `\t<key>provisioningProfiles</key>
\t<dict>
\t\t<key>${BUNDLE_ID}</key>
\t\t<string>${PROFILE_NAME}</string>
\t</dict>
`
    : ''
}\t<key>stripSwiftSymbols</key>
\t<true/>
\t<key>compileBitcode</key>
\t<false/>
</dict>
</plist>
`,
);

console.log(`[patch-ios-signing] ${BUNDLE_ID} uses ${usesManualProfile ? PROFILE_NAME : 'automatic signing'} (${TEAM_ID}).`);
